19	const COMPONENT_PREMIUM = 25;
20	const BLOCK_SIZE = 3;
21	const BLOCK_PREMIUM = 60;
22	
23	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
24	const PROCESSING_FEE = 5;
25	const ROUNDING_PRECISION = 6;
26	
27	const componentBasePremium = (count: number): number => {
28	  const blocks = Math.floor(count / BLOCK_SIZE);
29	  const loose = count % BLOCK_SIZE;
30	  return blocks * BLOCK_PREMIUM + loose * COMPONENT_PREMIUM;
31	};
32	
33	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
34	  const results = scenario.steps.map((step) => {
35	    const runeCount = step.items.filter((item) => item.type === "rune").length;
36	    const base = componentBasePremium(runeCount);
37	    const withFirstInsurance = base + base * FIRST_INSURANCE_SURCHARGE_RATE;
38	    const premium = Math.ceil(
39	      Number((withFirstInsurance + PROCESSING_FEE).toFixed(ROUNDING_PRECISION)),
40	    );
41	    return { premium };
42	  });
43	  return { results };
44	};
