1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Base premiums for single main items (base + 5 fee, newcomer: +10% first ins) ---
6	  // To isolate base premiums we use a long-standing customer's follow-up contract where
7	  // policy-wide modifiers are exercised separately; here we cover the raw base premium rule.
8	
9	  // Edge case: empty item list
10	  it("empty item list → premium 5 (only processing fee)", () => {
11	    const result = runScenario({
12	      customer: { yearsWithMHPCO: 0 },
13	      steps: [{ op: "quote", items: [] }],
14	    });
15	    expect(result.results[0]).toEqual({ premium: 5 });
16	  });
17	
18	  // Building block base premiums (components) — isolated base premium values
19	  it("2 runes → 50 G base premium", () => {
20	    const result = runScenario({
21	      customer: { yearsWithMHPCO: 0 },
22	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
23	    });
24	    // base 50 (2×25, no block) + 10% first insurance = 55, + 5 fee = 60
25	    expect(result.results[0]).toEqual({ premium: 60 });
26	  });
27	  it("3 runes → 60 G base premium (block applies)", () => {
28	    const result = runScenario({
29	      customer: { yearsWithMHPCO: 0 },
30	      steps: [
31	        { op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] },
32	      ],
33	    });
34	    // block of 3 → base 60, +10% first insurance = 66, +5 fee = 71
35	    expect(result.results[0]).toEqual({ premium: 71 });
36	  });
37	  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
38	  it.todo("7 runes → 175 G base premium");
39	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
40	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
41	
42	  // Integration: premium modifiers stacking
43	  it.todo("newcomer cursed sword (0 yrs, steel, ench 3) → premium 165");
44	  it.todo("long-standing customer 2nd contract (3 yrs, cursed sword steel ench 7) → premium 160");
45	
46	  // Modifier thresholds
47	  it.todo("customer with exactly 2 years → loyalty discount applies");
48	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
49	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
50	  it.todo("cursed sword with exactly enchantment 5 → both curse and high-enchant surcharges apply");
51	
52	  // Modifier scope on multi-item policies
53	  it.todo("cursed sword + plain amulet → 210 G before further modifiers and fee (curse on item base only)");
54	
55	  // Rounding
56	  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");
57	  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");
58	
59	  // --- Claim processing ---
60	
61	  // Standard reimbursement (no special clauses)
62	  it.todo("regular sword (steel, ench 3), damage 500 → payout 400 (full minus 100 deductible)");
63	  it.todo("rune (value 250), damage 200 → payout 100 (full minus 100 deductible, no special clause)");
64	
65	  // High enchantment clause
66	  it.todo("steel sword, enchantment 9, damage 1000 → payout 400 (50% then deductible)");
67	
68	  // Dragon material clause
69	  it.todo("dragon-material sword, enchantment 5, damage 800 → payout 700 (full then deductible)");
70	
71	  // Both clauses — 50% wins
72	  it.todo("dragon-material sword, enchantment 9, damage 1000 → payout 400 (50% wins, then deductible)");
73	  it.todo("dragon-material sword, exactly enchantment 8, damage 1000 → payout 400 (high-enchant applies, then deductible)");
74	
75	  // Deductible per damage event
76	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible once per item)");
77	
