79	  it.todo("policy covers sword + amulet → insurance sum 1600, cap 3200");
80	  it.todo("cursed sword → cap 2000 (based on unmodified insurance value)");
81	  it.todo("policy covers sword + 3 runes (block) → insurance sum 1750 (block discount does not affect sum)");
