92	  it.todo("quote with unknown item type (broomstick) → throws");
93	  it.todo("claim references item not in policy (amulet damaged, only sword insured) → throws");
94	  it.todo("claim references item with unknown type → throws");
95	  it.todo("claim damage amount negative (-200) → throws");
